        assertEquals(expectedDIDPairHost, didPairsHostCaptor.firstValue.toString())
        assertEquals(expectedDIDPairReceiver, didPairsReceiverCaptor.firstValue.toString())
        assertEquals("", didPairsNameCaptor.firstValue)

        // Validates Keys are backed up and restored properly, and passed to pluto for storage
        val keysDidCaptor1 = argumentCaptor<DID>()
        val keyPathIndexCaptor1 = argumentCaptor<Int>()
        val aliasCaptor1 = argumentCaptor<String>()
        val listKeysCaptor = argumentCaptor<List<StorableKey>>()
        verify(edgeAgent.pluto, times(2)).storePrismDIDAndPrivateKeys(
            keysDidCaptor1.capture(),
