                    receiver = DID("did:peer:2.Ez6LSrhfy5nfumryQUhCU9CRFZvEy3zZV2pUedwpUoYbeiZbq.Vz6MksfNehMay3PPDQEfaaeCotpgC5z9hCnbF6s8uYWUGjSYh.SeyJ0IjoiZG0iLCJzIjp7InVyaSI6Imh0dHA6Ly8xOTIuMTY4LjY4LjExMzo4MDAwL2RpZGNvbW0iLCJyIjpbXSwiYSI6WyJkaWRjb21tL3YyIl19fQ"),
                    name = ""
                )
            )
        )

        // Mediators verification
        val allMediators = realPluto.getAllMediators().first()
        assertEquals(1, allMediators.size)
        val expectedMediator = Mediator(
            mediatorDID = DID("did:peer:2.Ez6LSghwSE437wnDE1pt3X6hVDUQzSjsHzinpX3XFvMjRAm7y.Vz6Mkhh1e5CEYYq6JBUcTZ6Cp2ranCWRrv7Yax3Le4N59R6dd.SeyJ0IjoiZG0iLCJzIjp7InVyaSI6Imh0dHBzOi8vc2l0LXByaXNtLW1lZGlhdG9yLmF0YWxhcHJpc20uaW8iLCJhIjpbImRpZGNvbW0vdjIiXX19.SeyJ0IjoiZG0iLCJzIjp7InVyaSI6IndzczovL3NpdC1wcmlzbS1tZWRpYXRvci5hdGFsYXByaXNtLmlvL3dzIiwiYSI6WyJkaWRjb21tL3YyIl19fQ"),
            hostDID = DID("did:peer:2.Ez6LSok96TA4orHQXSMHZj3mqyUuVLMfLfGGqj27i1giErbXL.Vz6Mku5mY1GuJ9AN2vvDwjMv5QUC2zqKVRPCcbmJVYTFTCFmr"),
            routingDID = DID("did:peer:2.Ez6LSghwSE437wnDE1pt3X6hVDUQzSjsHzinpX3XFvMjRAm7y.Vz6Mkhh1e5CEYYq6JBUcTZ6Cp2ranCWRrv7Yax3Le4N59R6dd.SeyJ0IjoiZG0iLCJzIjp7InVyaSI6Imh0dHBzOi8vc2l0LXByaXNtLW1lZGlhdG9yLmF0YWxhcHJpc20uaW8iLCJhIjpbImRpZGNvbW0vdjIiXX19.SeyJ0IjoiZG0iLCJzIjp7InVyaSI6IndzczovL3NpdC1wcmlzbS1tZWRpYXRvci5hdGFsYXByaXNtLmlvL3dzIiwiYSI6WyJkaWRjb21tL3YyIl19fQ")
        )
        val actualMediator = allMediators.first()
        assertEquals(expectedMediator.mediatorDID, actualMediator.mediatorDID)
        assertEquals(expectedMediator.hostDID, actualMediator.hostDID)
        assertEquals(expectedMediator.routingDID, actualMediator.routingDID)

        // Link secret verification
        val linkSecret = realPluto.getLinkSecret().first()
        assertEquals("40960368705011900020984253500979753785333739067716460047393316855560515114468", linkSecret)

        // Credentials verification
        val allCredentials = realPluto.getAllCredentials().first()
        assertEquals(2, allCredentials.size)
        var jwtCounter = 0
        var anoncredsCounter = 0
        allCredentials.forEach { cred ->
            when (cred.restorationId) {
                RestorationID.JWT.value -> {
                    jwtCounter++
                }

                RestorationID.ANONCRED.value -> {
                    anoncredsCounter++
                }
            }
        }
        assertEquals(1, jwtCounter)
        assertEquals(1, anoncredsCounter)

        // Keys verification
        val allKeys = realPluto.getAllPrivateKeys().first()
        assertEquals(6, allKeys.size)
        var ed25519Counter = 0
        var x25519Counter = 0
        var secp256k1Counter = 0
        allKeys.forEach { storablePrivateKey ->
            when (storablePrivateKey.restorationIdentifier) {
                "ed25519+priv" -> {
                    ed25519Counter++
                }

                "x25519+priv" -> {
                    x25519Counter++
                }

                "secp256k1+priv" -> {
                    secp256k1Counter++
                }
            }
        }
        assertEquals(2, ed25519Counter)
        assertEquals(2, x25519Counter)
        assertEquals(2, secp256k1Counter)

        // Messages verification
        val allMessages = realPluto.getAllMessages().first()
        assertEquals(8, allMessages.size)
    }

